"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[2256],{55:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/docs/intro","label":"Overview","docId":"intro","unlisted":false},{"type":"link","href":"/docs/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"category","label":"Installation","collapsed":false,"items":[{"type":"link","href":"/docs/getting-started-helm","label":"Using Helm","docId":"getting-started-helm","unlisted":false}],"collapsible":true},{"type":"link","href":"/docs/concepts","label":"Core Concepts","docId":"concepts","unlisted":false},{"type":"category","label":"Authentication & Permissions","collapsed":true,"items":[{"type":"link","href":"/docs/guides/permissions","label":"Permissions Overview","docId":"guides/permissions","unlisted":false},{"type":"link","href":"/docs/guides/configure-iam","label":"Configure IAM Permissions","docId":"guides/configure-iam","unlisted":false}],"collapsible":true},{"type":"category","label":"Managing Resources","collapsed":false,"items":[{"type":"link","href":"/docs/guides/create-resource","label":"Create an ACK Resource","docId":"guides/create-resource","unlisted":false},{"type":"link","href":"/docs/guides/readonly","label":"ReadOnly Resources","docId":"guides/readonly","unlisted":false},{"type":"link","href":"/docs/guides/deletion-policy","label":"Deletion Policy","docId":"guides/deletion-policy","unlisted":false},{"type":"link","href":"/docs/guides/multi-region","label":"Resource Region","docId":"guides/multi-region","unlisted":false},{"type":"link","href":"/docs/guides/cross-account","label":"Granular IAM Roles","className":"sidebar-item-new","docId":"guides/cross-account","unlisted":false},{"type":"link","href":"/docs/guides/adoption","label":"Resource Adoption","docId":"guides/adoption","unlisted":false},{"type":"link","href":"/docs/guides/field-export","label":"Field Export","docId":"guides/field-export","unlisted":false},{"type":"link","href":"/docs/guides/kro","label":"Using ACK with kro","className":"sidebar-item-new","docId":"guides/kro","unlisted":false}],"collapsible":true},{"type":"category","label":"Controller Configuration","collapsed":true,"items":[{"type":"link","href":"/docs/guides/helm-values","label":"Helm Chart Values Reference","docId":"guides/helm-values","unlisted":false},{"type":"link","href":"/docs/guides/feature-gates","label":"Feature Gates","docId":"guides/feature-gates","unlisted":false},{"type":"link","href":"/docs/guides/performance","label":"Controller Performance","docId":"guides/performance","unlisted":false}],"collapsible":true}]},"docs":{"concepts":{"id":"concepts","title":"Core Concepts","description":"Understanding these ACK-specific concepts will help you effectively manage AWS infrastructure from Kubernetes.","sidebar":"tutorialSidebar"},"contributing":{"id":"contributing","title":"Contributing","description":"Coming soon..."},"getting-started":{"id":"getting-started","title":"Getting Started","description":"Get started with ACK by installing a controller using Helm. ACK works on any Kubernetes cluster including Amazon EKS, GKE, AKS, on-premises clusters, or local development environments.","sidebar":"tutorialSidebar"},"getting-started-helm":{"id":"getting-started-helm","title":"Self-Managed with Helm","description":"This guide shows you how to install ACK controllers yourself using Helm. This method works on any Kubernetes cluster and gives you full control over controller configuration.","sidebar":"tutorialSidebar"},"guides/adoption":{"id":"guides/adoption","title":"Resource Adoption","description":"Resource adoption allows you to import existing AWS resources into ACK management without recreating them. This is useful when you have pre-existing AWS infrastructure that you want to manage through Kubernetes.","sidebar":"tutorialSidebar"},"guides/alpha-features":{"id":"guides/alpha-features","title":"Alpha Features","description":"Coming soon..."},"guides/carm":{"id":"guides/carm","title":"CARM with IAMRoleSelectors","description":"Coming soon..."},"guides/configure-iam":{"id":"guides/configure-iam","title":"Configure IAM Permissions","description":"ACK controllers need AWS IAM permissions to manage resources. This guide shows you how to configure IAM permissions using either EKS Pod Identity (recommended for EKS 1.24+) or IRSA (traditional method).","sidebar":"tutorialSidebar"},"guides/create-resource":{"id":"guides/create-resource","title":"Create an ACK Resource","description":"This guide shows you how to create and manage AWS resources using ACK. We\'ll use S3 buckets and DynamoDB tables as examples, but the same patterns apply to all ACK resources.","sidebar":"tutorialSidebar"},"guides/cross-account":{"id":"guides/cross-account","title":"Granular IAM Roles","description":"ACK supports using multiple IAM roles with fine-grained control over which role is used for different resources or namespaces. This enables scenarios like managing resources across multiple AWS accounts or using different permission sets within the same account.","sidebar":"tutorialSidebar"},"guides/debugging":{"id":"guides/debugging","title":"Debugging","description":"Coming soon..."},"guides/deletion-policy":{"id":"guides/deletion-policy","title":"Deletion Policy","description":"Deletion policies control what happens to AWS resources when you delete their Kubernetes custom resources. By default, ACK deletes the AWS resource when you delete the Kubernetes resource, but you can configure it to retain the AWS resource instead.","sidebar":"tutorialSidebar"},"guides/drift":{"id":"guides/drift","title":"Recovering from Drift","description":"Coming soon..."},"guides/feature-gates":{"id":"guides/feature-gates","title":"Feature Gates","description":"ACK controllers support feature gates that enable or disable specific functionality. Feature gates allow you to try experimental features or opt into beta features.","sidebar":"tutorialSidebar"},"guides/field-export":{"id":"guides/field-export","title":"Field Export","description":"The FieldExport resource allows you to copy any spec or status field from an ACK resource into a Kubernetes ConfigMap or Secret. This bridges the gap between managing AWS resources and using their properties in your applications.","sidebar":"tutorialSidebar"},"guides/helm-values":{"id":"guides/helm-values","title":"Helm Chart Values Reference","description":"This page provides a comprehensive reference for all configurable values in ACK service controller Helm charts. These values allow you to customize controller deployment, behavior, and integration with your Kubernetes cluster and AWS environment.","sidebar":"tutorialSidebar"},"guides/iam-role-selector":{"id":"guides/iam-role-selector","title":"IAMRoleSelector","description":"Coming soon..."},"guides/kro":{"id":"guides/kro","title":"Using ACK with kro","description":"kro is a Kubernetes Resource Orchestrator that lets you compose multiple Kubernetes resources into a single, reusable unit. When combined with ACK, kro enables you to build complete AWS infrastructure stacks that can be deployed with a single custom resource.","sidebar":"tutorialSidebar"},"guides/leader-election":{"id":"guides/leader-election","title":"Managing Multiple Instances with Leader Election","description":"Coming soon..."},"guides/monitoring":{"id":"guides/monitoring","title":"Monitoring & Metrics","description":"Coming soon..."},"guides/multi-region":{"id":"guides/multi-region","title":"Multi-Region","description":"ACK controllers can manage resources across multiple AWS regions using a single controller deployment.","sidebar":"tutorialSidebar"},"guides/performance":{"id":"guides/performance","title":"Controller Performance","description":"Understanding controller performance characteristics and configuration options helps you optimize ACK for your workload scale and AWS service quotas.","sidebar":"tutorialSidebar"},"guides/permissions":{"id":"guides/permissions","title":"Permissions Overview","description":"ACK service controllers require two different authorization systems: Kubernetes RBAC and AWS IAM. Kubernetes RBAC governs access to Kubernetes resources, while AWS IAM policies control access to AWS resources. These systems operate independently - the Kubernetes user making kubectl calls has no association with the IAM role. Instead, the IAM role is attached to the service account running the controller pod.","sidebar":"tutorialSidebar"},"guides/readonly":{"id":"guides/readonly","title":"ReadOnly Resources","description":"ReadOnly mode allows you to observe AWS resources without ACK managing them. When a resource is marked as read-only, ACK will sync the resource status from AWS but will never create, update, or delete the underlying AWS resource.","sidebar":"tutorialSidebar"},"guides/status":{"id":"guides/status","title":"Understanding Status","description":"Coming soon..."},"guides/tags":{"id":"guides/tags","title":"Managing Tags on AWS Resources","description":"Coming soon..."},"guides/troubleshooting":{"id":"guides/troubleshooting","title":"Troubleshooting","description":"Coming soon..."},"guides/upgrades":{"id":"guides/upgrades","title":"Upgrades","description":"Coming soon..."},"installation":{"id":"installation","title":"Installation","description":"Detailed installation guide coming soon..."},"intro":{"id":"intro","title":"Overview","description":"AWS Controllers for Kubernetes (ACK) lets you define and manage AWS service resources directly from Kubernetes. Traditionally, when building applications on Kubernetes, you need to juggle multiple tools: Kubernetes manifests for your workloads, and separate tools like CloudFormation, Terraform, or the AWS Console for infrastructure like databases, queues, and storage. This split creates operational complexity and breaks the unified workflow that makes Kubernetes powerful. ACK solves this by bringing AWS services into Kubernetes as native resources, so you can manage everything  -  applications and infrastructure  -  using the same declarative YAML manifests and GitOps workflows you already know.","sidebar":"tutorialSidebar"}}}}')}}]);